css:
.sp-monthly-summary-print { font-size: 12px; color: #111; }
.sp-monthly-summary-print .title { text-align: center; font-size: 22px; font-weight: 700; margin-bottom: 18px; }
.sp-monthly-summary-print .meta-wrap { margin-bottom: 14px; }
.sp-monthly-summary-print .meta-table { width: 100%; border-collapse: collapse; table-layout: fixed; }
.sp-monthly-summary-print .meta-table > tbody > tr > td { border: none; padding: 0; vertical-align: top; }
.sp-monthly-summary-print .meta-half { width: 50%; padding-right: 12px; }
.sp-monthly-summary-print .meta-half-right { width: 50%; padding-left: 12px; }
.sp-monthly-summary-print .meta-inner { width: 100%; border-collapse: collapse; table-layout: fixed; }
.sp-monthly-summary-print .meta-inner col.meta-col-label { width: 38%; }
.sp-monthly-summary-print .meta-inner col.meta-col-value { width: 62%; }
.sp-monthly-summary-print .meta-inner td { border: none; padding: 4px 0; vertical-align: baseline; }
.sp-monthly-summary-print .meta-label { font-weight: 700; white-space: nowrap; padding-right: 8px; }
.sp-monthly-summary-print .meta-value { border-bottom: 1px solid #111; height: 18px; padding-bottom: 2px; white-space: nowrap; overflow: hidden; }
.sp-monthly-summary-print .summary-table { width: 100%; border-collapse: collapse; margin-bottom: 14px; }
.sp-monthly-summary-print .summary-table th,
.sp-monthly-summary-print .summary-table td { border: 1px solid #111; padding: 4px 6px; vertical-align: top; }
.sp-monthly-summary-print .summary-table th { background: #f2f2f2; text-align: center; }
.sp-monthly-summary-print .summary-table .date-col { text-align: left; white-space: nowrap; }
.sp-monthly-summary-print .summary-table .num { text-align: right; white-space: nowrap; }
.sp-monthly-summary-print .summary-table .grand-total-row td { background: #fcefd8; font-weight: 700; }
